import { Component, ElementRef, EventEmitter, HostListener, Input, Optional, Output, QueryList, ViewChildren } from '@angular/core';
import { FormArray, FormBuilder, FormGroup, Validators } from '@angular/forms';
import { NgbActiveModal, NgbModal } from '@ng-bootstrap/ng-bootstrap';
import { Subject, Subscription, debounceTime } from 'rxjs';
import { CommonService } from '../../../../../../services/common.service';
import { SubjectService } from '../../../../../../services/subject.service';
import { MarkaziaVoucherService } from '../../../markazia-vouchers/services/markazia-voucher.service';
import { DatePipe } from '@angular/common';
import { ToastrService } from 'ngx-toastr';

@Component({
  selector: 'voucher',
  templateUrl: './voucher.component.html',
  styleUrls: ['./voucher.component.scss']
})
export class VoucherComponent {
  invalidFileType = '';
  fileTypes = ['image/jpeg', 'image/jpg', 'image/png', 'application/pdf'];
  @Input() accounts = [];
  @Input() currencies: [];
  vouchersList = [];
  filesArray = [];
  voucherForm: FormGroup;
  uploadedFiles: string[] = [];
  @Input() recentFormValues
  @Input() isPending: boolean;
  @Input() otherData;
  filesSubscription = new Subscription();
  isLoading = false;
  searchIndex: number;
  markaziaVoucher;
  @Output() amountEvent: EventEmitter<any> = new EventEmitter<any>();
  @Output() formValueEvent: EventEmitter<any> = new EventEmitter<any>();
  @HostListener('document:keydown.tab', ['$event']) onKeydownHandler() {
    this.handleTabKeyDown();
  }
  private searchSequenceSubject = new Subject<string>();
  @ViewChildren('fileInput') inputRefList: QueryList<any>;
  constructor(private fb: FormBuilder,
    private _modalService: NgbModal,
    @Optional() public _activeModal: NgbActiveModal,
    private _datePipe: DatePipe,
    public _commonService: CommonService,
    public _subjectService: SubjectService,
    private _toastr: ToastrService,
    private _vocuherService: MarkaziaVoucherService) {
    this.searchSequenceSubject.pipe(debounceTime(1000)).subscribe((term: string) => { this.getMarkaziaVouchers(term); });
  }
  ngOnInit() {
    console.log(this.otherData);
    this.initForm();
    this.voucherForm.statusChanges.subscribe(x => {
      this.voucherForm.markAllAsTouched();
      this.formValueEvent.emit({ values: this.voucherForm.getRawValue(), touched: x == 'VALID' ? false : true })
    })
  }
  initForm() {
    this.voucherForm = this.fb.group({
      voucherArray: this.fb.array([this.initVoucherFormgroup()])
    })
    if (this.recentFormValues?.voucher?.voucherArray?.length) {
      let values = this.recentFormValues['voucher'].voucherArray;
      let formArray = (this.voucherForm.get('voucherArray') as FormArray);
      formArray.removeAt(0);
      for (let item of values) {
        formArray.push(this.initVoucherFormgroup(item));
      }
    }
  }
  ngOnDestroy() {
    if (this.recentFormValues?.voucher?.voucherArray[0]?.amountJod > 0) {
      this.formValueEvent.emit({ values: this.voucherForm.getRawValue(), touched: false })
    }
  }
  handleAmountFocus() {
    this.voucherForm.markAllAsTouched();
  }
  initVoucherFormgroup(item?) {
    return this.fb.group({
      voucherSequence: [item?.voucherSequence || ''],
      voucherNumber: [item?.voucherNumber || '', [Validators.required]],
      amountJod: [{ value: item?.amountJod || '', disabled: true }, [Validators.required]],
      currencyId: [{ value: 9001, disabled: true }],
      brand: [{ value: item?.brand || '', disabled: true }],
      campaign: [{ value: item?.campaign || '', disabled: true }],
      validityTo: [{ value: item?.validityTo || '', disabled: true }],
    });
  }
  handleSearch(event, index) {
    let value = event.target.value;
    this.searchIndex = index;
    if (value) {
      this.searchSequenceSubject.next(value);
    }
    else {
      this.voucherArray.at(this.searchIndex).reset();
    }
  }
  getMarkaziaVouchers(value) {
    this.isLoading = true;
    let params = `?pageSize=1000&sequence=${value}`;
    this._vocuherService.getMarkaziaVoucherList(params).pipe(debounceTime(500)).subscribe((response: any) => {
      let voucher = response.data[0];
      this.markaziaVoucher = voucher;
      let obj = {
        amountJod: voucher?.markaziaVAmount,
        voucherSequence: voucher?.markaziaVSequence,
        brand: voucher?.brand?.brand,
        campaign: voucher?.markaziaVCampaign,
        validityTo: this._datePipe.transform(voucher?.markaziaVValidityTo, 'mediumDate'),
      }
      if (voucher) {
        if (voucher.markaziaVStatus == 39001) { //VALID VOUCHER
          this.voucherArray.at(this.searchIndex).patchValue(obj);
          if (obj?.amountJod > this.otherData.grandAmount) {
            this.voucherArray.at(this.searchIndex).get('amountJod').enable();
          }
          else {
            this.voucherArray.at(this.searchIndex).get('amountJod').disable();
            this.sendAmount();
          }
        }
        else {
          this._toastr.error('Invalid Voucher', 'Invalid');
          this.voucherArray.at(this.searchIndex).reset();
          this.sendAmount();
        }
      }
      else {
        this.voucherArray.at(this.searchIndex).reset();
        this._toastr.error('No voucher found', 'Not Found');
        this.sendAmount();
      }
    }).add(() => this.isLoading = false);
  }
  removeItem(i) {
    this.voucherArray.removeAt(i);
    this.sendAmount();
  }
  get voucherArray() {
    return this.voucherForm ? this.voucherForm.get('voucherArray') as FormArray : null;
  }
  handleTabKeyDown() {
    if (this.voucherForm.invalid) {
      return;
    }
    if (this.otherData['amountExceeded']) {
      return;
    }
    if (!this.otherData?.isMultiCollect)
      this.addNewRow();

  }
  addNewRow() {
    this.voucherArray.push(this.initVoucherFormgroup());
    this.voucherForm.markAsUntouched();
  }
  handleSubmit() {
    if (this.voucherForm.invalid) {
      this.voucherForm.markAllAsTouched();
    }
    else {
      this.formValueEvent.emit({ values: this.voucherForm.getRawValue(), submit: true })
    }
  }
  get f() {
    return this.voucherForm.controls;
  }
  sendAmount() {
    this.calculateAmount();
  }
  calculateAmount() {
    let amount = 0;
    for (let item of this.voucherArray.controls) {
      let formGroup = item as FormGroup;
      amount += parseFloat((+formGroup.controls['amountJod'].value).toFixed(3));
    }
    this.amountEvent.emit({ amount });
  }
  resetForm() {
    this.voucherForm.reset();
    this.voucherForm.markAsUntouched();
    this.formValueEvent.emit({ values: this.voucherForm.getRawValue(), touched: false, reset: true });
    this.amountEvent.emit({ amount: 0 });
  }
  closeModal() {
    if (this._activeModal)
      this._activeModal.close()
    else
      this._commonService.NavigateToRoute(`/${this.otherData?.redirectRoute}`)
  }
}

