import { Component, EventEmitter, Output } from '@angular/core';
import { FormBuilder, FormGroup, Validators } from '@angular/forms';
import { NgbActiveModal } from '@ng-bootstrap/ng-bootstrap';
import { CollectService } from '../../../../services/collect.service';
import { Subject, Subscription, debounceTime, distinctUntilChanged, switchMap } from 'rxjs';

@Component({
  selector: 'app-add-new-customer',
  templateUrl: './add-new-customer.component.html',
  styleUrls: ['./add-new-customer.component.scss']
})
export class AddNewCustomerComponent {
  responseMessage;
  isSubmitted = false;
  isNewCustomer = false;
  isIndividual = true;
  customerList = [];
  formGroup: FormGroup;
  selectedCustomer: number = 0;
  selectedItem;
  isCreditCustomer = false;
  titleList = [/*{ value: 0, text: 'Messrs' }, */{ value: 1, text: 'Mr.' }, { value: 2, text: 'Ms.' }, { value: 11, text: 'Dr.' }, { value: 12, text: 'Eng.' }];
  @Output() sendData = new EventEmitter();
  private searchSubject = new Subject<string>();
  private searchSubscription = new Subscription();
  constructor(private _collectService: CollectService, private fb: FormBuilder, public _activeModal: NgbActiveModal) { }
  ngOnInit() {
    this.initCustomerForm();
    this.searchSubscription = this.searchSubject.pipe(
      debounceTime(500), distinctUntilChanged(), switchMap((value: string) => this._collectService.getMarkaziaCustomers(value, Number(this.isCreditCustomer)))
    ).subscribe(response => {
      this.customerList = response['data'];
    });
  }
  initCustomerForm() {
    this.formGroup = this.fb.group({
      title: [null, [Validators.required]],
      fname: ['', [Validators.required, Validators.pattern('^[a-zA-Z]*$')]],
      sname: ['', [Validators.required, Validators.pattern('^[a-zA-Z]*$')]],
      thName: ['', [Validators.required, Validators.pattern('^[a-zA-Z]*$')]],
      fourthName: ['', [Validators.required, Validators.pattern('^[a-zA-Z]*$')]],
      gender: ['0'],
      customerCategory: ['1'],
      mobile: ['', [Validators.required, Validators.minLength(9), Validators.maxLength(10)]],
    })
  }
  ngOnDestroy() {
    this.searchSubscription.unsubscribe();
  }
  handleCreditCustomerChange(event, value) {
    if (value) {
      this._collectService.getMarkaziaCustomers(value, Number(this.isCreditCustomer)).subscribe(response => {
        this.customerList = response['data'];
      });
    }
  }
  handleSearch(event: any) {
    const value = event.target.value;
    this.searchSubject.next(value);
  }
  handleCetegoryChange(value) {
    this.isIndividual = value == 1 ? true : false;
    if (this.isIndividual) {
      this.f.get('title').setValidators([Validators.required]);
      this.f.get('title').updateValueAndValidity();
      this.f.get('sname').setValidators([Validators.required, Validators.pattern('^[a-zA-Z]*$')]);
      this.f.get('sname').updateValueAndValidity();
      this.f.get('thName').setValidators([Validators.required, Validators.pattern('^[a-zA-Z]*$')]);
      this.f.get('thName').updateValueAndValidity();
      this.f.get('fourthName').setValidators([Validators.required, Validators.pattern('^[a-zA-Z]*$')]);
      this.f.get('fourthName').updateValueAndValidity();
    }
    else {
      this.f.get('title').clearValidators();
      this.f.get('title').updateValueAndValidity();
      this.f.get('sname').clearValidators();
      this.f.get('sname').updateValueAndValidity();
      this.f.get('thName').clearValidators();
      this.f.get('thName').updateValueAndValidity();
      this.f.get('fourthName').clearValidators();
      this.f.get('fourthName').updateValueAndValidity();
    }
  }

  removeByIndex(str, index) {
    return str.slice(0, index) + str.slice(index + 1);
  }
  saveCustomer() {
    if (this.formGroup.invalid) {
      this.formGroup.markAllAsTouched();
      return;
    }
    else {
      this.isSubmitted = true;
      let obj;
      let values = this.formGroup.value;
      let mobile = values?.mobile;
      if (mobile.charAt(0) == 0) {
        mobile = this.removeByIndex(values?.mobile, 0);
      }
      values = { ...values, customerCategory: +values?.customerCategory, gender: +values?.customerCategory, mobile: `962${mobile}` }
      if (this.isIndividual)
        obj = values;
      else {
        obj = {
          corporateName: values?.fname,
          customerCategory: values?.customerCategory,
          mobile: values?.mobile,
        }
      }
      this._collectService.addMarkaziaCustomer(obj).subscribe(response => {
        this.isSubmitted = false;
        console.log(response);
        if (response['isSuccess']) {
          this.sendData.emit(response['data'])
          this._activeModal.close();
        }
      }, (error => {
        this.isSubmitted = false;
        this.responseMessage = error.error?.errors[0]?.ErrorMessageEn;
        setTimeout(() => {
          this.responseMessage = '';
        }, 5000)
      }))
    }
  }
  selectCustomer(item) {
    this.selectedItem = item;
    this.selectedCustomer = item?.customerNo;
  }
  handleSelect() {
    let data = { customerNo: this.selectedItem?.customerNo, corporateName: this.selectedItem?.customerName, mobile: this.selectedItem?.customerPhone }
    this.sendData.emit(data);
    this._activeModal.close();
  }
  addNewCustomer() {
    this.isNewCustomer = true;
  }
  goBack() {
    this.isNewCustomer = false;
  }
  get f() {
    return this.formGroup;
  }
}
