import { Component, EventEmitter, Input, Optional, Output } from '@angular/core';
import { NgbActiveModal, NgbModal } from '@ng-bootstrap/ng-bootstrap';
import { CommonService } from '../../../../../../services/common.service';
import { SubjectService } from '../../../../../../services/subject.service';
import { ModalPayDoneComponent } from '../../modal-payment/modal-pay-done/modal-pay-done.component';
import { CollectService } from '../../services/collect.service';
import { NgxSpinnerService } from 'ngx-spinner';

@Component({
  selector: 'on-account',
  templateUrl: './on-account.component.html',
  styleUrls: ['./on-account.component.scss']
})
export class OnAccountComponent {
  @Input() otherData;
  isPending: boolean;
  @Output() eventData = new EventEmitter();
  cashierNotes = '';
  constructor(
    @Optional() public _activeModal: NgbActiveModal,
    public _modalService: NgbModal,
    public _collectService: CollectService,
    public _subjectService: SubjectService,
    private _commonService: CommonService,
    private _spinner: NgxSpinnerService,

  ) {

  }
  ngOnInit() {
    console.log(this.otherData);
  }
  closeModal() {
    if (this._activeModal)
      this._activeModal.close()
    else
      this._commonService.NavigateToRoute(`/${this.otherData?.redirectRoute}`)
  }
  confirm() {
    this._spinner.show();
    if (this.otherData['isMultiCollect']) {
      this.isPending = true;
      let obj = {
        ordersCollection: {
          orderCollectionType: this.otherData?.collectionType,
          orderNo: this.otherData?.orderNo,
        },
        ordersOnAccountCollection: {
          onAccountCollectionJod: this.otherData?.grandAmount,
          onAccountPayerName: this.otherData?.customerName,
        }
      }
      this._collectService.collectionOrderV2MultiCollect(obj).subscribe(response => {
        if (response.isSuccess) {
          this.openSuccessModal('ok', response);
        } else {
          this.openSuccessModal('no', response);
        }
      }, (error: any) => {
        this.openSuccessModal('no', error);
      }).add(() => this._spinner.hide());
    }
    else {
      let orderId = 0;
      if (this.otherData?.collectionType == 7001) orderId = this.otherData.servicesSalesOrderNo || this.otherData.order?.servicesSalesOrderNo
      else if (this.otherData?.collectionType == 7003) orderId = this.otherData?.sparePartsSalesOrderOpportunityNo || this.otherData?.order?.sparePartsSalesOrderOpportunityNo
      this.isPending = true;
      let obj = {
        ordersCollection: {
          orderCollectionType: this.otherData?.collectionType,
          orderNo: orderId,
          isReplace: this.otherData?.isFromReturn,
          cashierNotes: this.cashierNotes,
        },
        ordersOnAccountCollection: {
          onAccountCollectionJod: this.otherData?.grandAmount || this.otherData?.order?.grandAmount,
          onAccountPayerName: this.otherData?.customer?.customerName,
        }
      }
      this._collectService.collectionOrderV2(obj).subscribe(response => {
        if (response.isSuccess) {
          this._subjectService.isCollectionPaymentDone.next(true);
          this._subjectService.collectedOrder.next({ orderId });
          this.openSuccessModal('ok', response);
        } else {
          this.openSuccessModal('no', response);
        }
      }, (error: any) => {
        this.openSuccessModal('no', error);
      }).add(() => this._spinner.hide());
    }
  }
  openSuccessModal(name, response?, error?) {
    this.isPending = false;
    const modalRef = this._modalService.open(ModalPayDoneComponent);
    modalRef.componentInstance.name = name;
    if ((this.otherData.collectionType == 7001 || this.otherData.collectionType == 7002 || this.otherData.collectionType == 7003) && !this.otherData['isMultiCollect']) {
      let receipt, invoice, summary;
      if (response.data.statusObj[0].lookupId == 10005) //partial status
        receipt = response.data?.receipt;
      else if (response.data.statusObj[0].lookupId == 10004) //collected status
      {
        receipt = response.data?.receipt;
        invoice = response.data?.invoices;
        summary = response.data?.summaryInvoice;
      }
      modalRef.componentInstance.data = {
        collectionType: this.otherData.collectionType,
        status: response.data.statusObj[0].lookupId,
        invoice, receipt, summary,
        invoiceType: this.otherData?.invoiceType?.toLowerCase()
      }
    }
    else if (this.otherData['isMultiCollect']) {
      modalRef.componentInstance.data = {
        collectionType: this.otherData?.collectionType,
        isMultiCollect: this.otherData['isMultiCollect'],
      }
    }
    else {
      modalRef.componentInstance.data = { collectionType: this.otherData.collectionType, invoices: response.data }
    }
    if (response) {
      if (response.error)
        modalRef.componentInstance.errors = response.error['errors'];
      else
        modalRef.componentInstance.response = response;
    }
    else
      modalRef.componentInstance.errors = error.error.errors || error.error.Errors;
  }

}
