import { Component, EventEmitter, HostListener, Input, Optional, Output } from '@angular/core';
import { AbstractControl, FormArray, FormBuilder, FormControl, FormGroup, Validators } from '@angular/forms';
import { NgbActiveModal } from '@ng-bootstrap/ng-bootstrap';
import { ToastrService } from 'ngx-toastr';
import { CommonService } from '../../../../../../services/common.service';
import { SubjectService } from '../../../../../../services/subject.service';
import { Subscription } from 'rxjs';
import * as _ from 'lodash';

@Component({
  selector: 'paymentCashForm',
  templateUrl: './cash.component.html',
  styleUrls: ['./cash.component.scss']
})
export class CashComponent {
  cashForm: FormGroup;
  sameCustomer: boolean;
  curruncyAry = [];
  currenciesArray = [];
  subscription = new Subscription();
  @Input() currencies = [];
  @Input() isPending: boolean;
  @Input() recentFormValues;
  @Input() otherData;
  @Output() amountEvent: EventEmitter<any> = new EventEmitter<any>();
  @Output() formValueEvent: EventEmitter<any> = new EventEmitter<any>();
  colllectedViaMachine = false;
  @HostListener('document:keydown.tab', ['$event']) onKeydownHandler() {
    this.handleTabKeyDown();
  }
  constructor(private fb: FormBuilder, @Optional() public _activeModal: NgbActiveModal, private _commonService: CommonService, public _subjectService: SubjectService) { }
  ngOnInit() {
    this.colllectedViaMachine = JSON.parse(localStorage.getItem('pos_mc'));
    this.initForm();
    this.cashForm.statusChanges.subscribe(x => {
      this.cashForm.markAllAsTouched();
      let touched;
      if (this.otherData?.reverse) touched = (x == 'VALID' || x == 'DISABLED') ? false : true;
      else touched = x == 'VALID' ? false : true;
      this.formValueEvent.emit({ values: this.cashForm.getRawValue(), touched })
    })
    if (this.recentFormValues?.cash?.cashArray?.length) {
      let formArray = this.cashForm.controls["cashArray"] as FormArray;
      formArray.removeAt(0);
      for (let item of this.recentFormValues?.cash?.cashArray) {
        formArray.push(this.initCashForm(item));
        this.currenciesArray.push(item['currencyId']);
      }
      // ONLY IN CASE OF REVERSE
      if (this.otherData?.reverse)
        this.disableReversedItems();
    }
    // ONLY IN CASE OF Refund
    if (this.otherData?.refund)
      this.cashArrControls.disable({ emitEvent: false });
  }
  disableReversedItems() {
    this.cashArrControls.controls.forEach((control: FormGroup) => {
      let isNew = control.get('isNew').value;
      if (!isNew)
        control.disable();
    })
  }
  ngOnDestroy() {
    this.subscription.unsubscribe();
    if (this.recentFormValues?.cash?.cashArray[0]?.collectedAmount > 0)
      this.formValueEvent.emit({ values: this.cashForm.getRawValue(), touched: false })
  }
  closeModal() {
    if (this._activeModal)
      this._activeModal.close()
    else
      this._commonService.NavigateToRoute(`/${this.otherData?.redirectRoute}`)
  }
  initForm() {
    this.cashForm = this.fb.group({
      cashArray: this.fb.array([this.initCashForm()])
    })
  }
  initCashForm(item?) {
    if (item) {
      return this.fb.group({
        currencyId: [item?.currencyId, [Validators.required]],
        collectedAmount: [item?.collectedAmount, [Validators.required, Validators.min(0.0000000000000001)]],
        vjod: item?.vjod,
        sameCustomer: [item?.sameCustomer],
        cashPayerName: [item?.cashPayerName, this.otherData.collectionType != 7004 && [Validators.required]],
        rate: [item?.rate],
        isReversed: [(item?.isReversed ?? item?.isReversed) || false],
        isNew: [(item?.isNew ?? item?.isNew) || false],
        lineNew: [(item?.lineNew ?? item?.lineNew) || false],
      });
    }
    else {
      return this.fb.group({
        currencyId: [9001, [Validators.required]],
        collectedAmount: [null, [Validators.required, Validators.min(0.0000000000000001)]],
        vjod: null,
        sameCustomer: [true],
        cashPayerName: [localStorage.getItem('pmcn') || 'No Customer', this.otherData.collectionType != 7004 && [Validators.required]],
        rate: [1],
        isReversed: [false],
        isNew: true,
        lineNew: true,
      });
    }
  }
  handleTabKeyDown() {
    if (this.otherData?.refund || this.cashForm.invalid) {
      return;
    }
    if (this.otherData['amountExceeded']) {
      return;
    }
    //NEW WILL BE ADDED IF ITS NO MULTI COLLECT
    if (!this.otherData?.isMultiCollect) {
      this.addNewCurrency();
    }
  }
  handleAmountFocus() {
    this.cashForm.markAllAsTouched();
  }
  chooseCurrency(event, i) {
    this.cashForm.markAllAsTouched();
    let control = this.cashArrControls.at(i).get('vjod');
    let value = +(this.cashArrControls.at(i).get('collectedAmount').value);
    let rate = +(event?.rate);
    let convertedAmount = (value * rate).toFixed(3);
    this.cashArrControls.at(i).get('rate').setValue(event?.rate);
    if (event?.lookupId == 9001) {
      control.setValue((value * 1).toFixed(3));
    } else if (event?.lookupId == 9002) {
      control.setValue(convertedAmount);
    } else if (event?.lookupId == 9003) {
      control.setValue(convertedAmount);
    }
    this.currenciesArray = [];
    for (let item of this.cashArrControls.controls) {
      let formGroup = item as FormGroup;
      this.currenciesArray.push(formGroup.controls['currencyId'].value);
    }
    this.calculateAmount();
  }
  handleAmountChange(i) {
    let vjod = this.cashArrControls.at(i).get('vjod');
    let value = +(this.cashArrControls.at(i).get('collectedAmount').value);
    let rate = +this.cashArrControls.at(i).get('rate').value;
    let convertedAmount = (value * rate).toFixed(3);
    vjod.setValue(convertedAmount);
    this.calculateAmount();
  }
  reverse(item: AbstractControl, index: number) {
    const previousFormGroup = this.cashArrControls.at(index) as FormGroup;
    if (previousFormGroup.invalid)
      return;
    const newFormGroup = this.fb.group({});
    Object.keys(previousFormGroup.controls).forEach(controlName => {
      const controlValue = _.cloneDeep(previousFormGroup.get(controlName)?.value);
      newFormGroup.addControl(controlName, new FormControl(controlValue));
    });
    let amountJOD = +(previousFormGroup.get('vjod').value);
    let negativeValue = (previousFormGroup.get('collectedAmount').value) * -1;
    let negativeJODValue = amountJOD * -1;
    newFormGroup.patchValue({
      vjod: negativeJODValue,
      collectedAmount: negativeValue,
      isReversed: true,
      lineNew: true,
    })
    previousFormGroup.get('isReversed').setValue(true);
    previousFormGroup.get('lineNew').setValue(false);
    this.cashArrControls.insert(index + 1, newFormGroup);
    (this.cashArrControls.at(index) as FormGroup).disable();
    (this.cashArrControls.at(index + 1) as FormGroup).disable();
    this.calculateAmount();
  }
  calculateAmount() {
    let amount = 0;
    for (let item of this.cashArrControls.controls) {
      let formGroup = item as FormGroup;
      amount += +(formGroup.controls['vjod'].getRawValue());
    }
    this.amountEvent.emit({ amount });
  }
  removeItem(i) {
    if (this.otherData.refund) return;
    this.cashArrControls.removeAt(i);
    this.currenciesArray = [];
    for (let item of this.cashArrControls.controls) {
      let formGroup = item as FormGroup;
      this.currenciesArray.push(formGroup.controls['currencyId'].value);
    }
    this.calculateAmount();
  }
  addNewCurrency() {
    let length = this.cashArrControls.length + 1;
    if (this.otherData?.reverse)
      length = length - this.getDisabledFormGroupCount();
    if (length <= this.currencies.length) {
      this.cashArrControls.push(this.initCashForm())
    }
    this.cashForm.markAsUntouched();
  }
  getDisabledFormGroupCount(): number {
    let disabledCount = 0;
    this.cashArrControls.controls.forEach(control => {
      if (control.disabled) disabledCount++;
    });
    return disabledCount;
  }
  resetForm() {
    this.cashArrControls.clear();
    this.cashArrControls.push(this.initCashForm());
    this.cashForm.markAsUntouched();
    this.formValueEvent.emit({ values: this.cashForm.getRawValue(), touched: false, reset: true });
    this.calculateAmount();
    this.currenciesArray = [];
    this.amountEvent.emit({ amount: 0 });
  }
  isSameCustomer(event, index) {
    let formGroup = this.cashArrControls.at(index) as FormGroup;
    if (event.target.checked) {
      if (this.otherData.collectionType == 7004)
        formGroup.controls['cashPayerName'].setValue('No Customer');
      else {
        let customerName = localStorage.getItem('pmcn');
        formGroup.controls['cashPayerName'].setValue(customerName);
      }
    }
    else {
      formGroup.controls['cashPayerName'].setValue('');
    }
  }
  get cashArrControls() {
    return this.cashForm ? this.cashForm.get('cashArray') as FormArray : null;
  }
  get f() {
    return this.cashForm.controls;
  }
  handleSubmit() {
    if (this.cashForm.invalid) {
      this.cashForm.markAllAsTouched();
    }
    else {
      this.formValueEvent.emit({ values: this.cashForm.getRawValue(), submit: true })
    }
  }
}
