import { Component, ElementRef, EventEmitter, HostListener, Input, Optional, Output, QueryList, ViewChildren } from '@angular/core';
import { AbstractControl, FormArray, FormBuilder, FormControl, FormGroup, Validators } from '@angular/forms';
import { NgbActiveModal, NgbModal } from '@ng-bootstrap/ng-bootstrap';
import { Subscription } from 'rxjs';
import { CommonService } from '../../../../../../services/common.service';
import { SubjectService } from '../../../../../../services/subject.service';
import { CollectService } from '../../services/collect.service';
import { ViewFileComponent } from '../view-file/view-file.component';
import * as _ from 'lodash';

@Component({
  selector: 'bankTransfer',
  templateUrl: './bank-transfer.component.html',
  styleUrls: ['./bank-transfer.component.scss']
})
export class BankTransferComponent {
  invalidFileType = '';
  fileTypes = ['image/jpeg', 'image/jpg', 'image/png', 'application/pdf'];
  @Input() accounts = [];
  @Input() currencies: [];
  filesArray = [];
  bankTransferForm: FormGroup;
  uploadedFiles: string[] = [];
  @Input() recentFormValues
  @Input() isPending: boolean;
  @Input() otherData;
  filesSubscription = new Subscription();
  @Output() amountEvent: EventEmitter<any> = new EventEmitter<any>();
  @Output() formValueEvent: EventEmitter<any> = new EventEmitter<any>();
  @HostListener('document:keydown.tab', ['$event']) onKeydownHandler() {
    this.handleTabKeyDown();
  }
  @ViewChildren('fileInput') inputRefList: QueryList<any>;
  colllectedViaMachine = false;
  constructor(private fb: FormBuilder, private _modalService: NgbModal, @Optional() public _activeModal: NgbActiveModal,
    public _commonService: CommonService, public _subjectService: SubjectService, private _collectService: CollectService) {
  }
  ngOnInit() {
    this.colllectedViaMachine = JSON.parse(localStorage.getItem('pos_mc'));
    this.getBankAccounts();
    this.accounts = [{ id: 1, name: 78954 }, { id: 1, name: 78954 },]
    this.initForm();
    this.bankTransferForm.statusChanges.subscribe(x => {
      let touched;
      if (this.otherData?.reverse) touched = (x == 'VALID' || x == 'DISABLED') ? false : true;
      else touched = x == 'VALID' ? false : true;
      this.bankTransferForm.markAllAsTouched();
      this.formValueEvent.emit({ values: this.bankTransferForm.getRawValue(), touched })
    })
    // ONLY IN CASE OF Refund
    if (this.otherData?.refund)
      this.bankArrControls.disable({ emitEvent: false });
    // ONLY IN CASE OF REVERSE
    if (this.otherData?.reverse) {
      this.disableReversedItems();
    }
  }
  disableReversedItems() {
    this.bankArrControls.controls.forEach((control: FormGroup) => {
      // THIS OPERATION IS DONE BECAUSE WHILE REVERSE IN BELOW CONTROLS THE VALUE IS FULL URL OF FILE FROM SERVER,
      // SO IN TEMPLATE WE NEED TO SHOW TEXT OF ATTACHMENT ONLY INSTEAD OF FULL URL.
      let attachment = control.get('attachment');
      // PUSH VALUES ARRAY TO MANUPLATE THE ARRAY ACCORDING TO FORMARRY LENGTH
      let attachmentValue = attachment.getRawValue();
      this.filesArray.push(attachmentValue);
      if (attachmentValue) {
        attachment.setValue('Attachment');
      }
      // END HERE
      let isNew = control.get('isNew').value;
      if (!isNew)
        control.disable();
    })
  }
  getBankAccounts() {
    let params = `?AccountType=15001&currencyId=9001&Status=2001&PageNo=0&PageSize=1000`
    this._collectService.getBankAccounts(params).subscribe((response: any) => {
      if (response.isSuccess) {
        this.accounts = response['data'].map(x => { return { id: x.accountId, name: x.bankNameEnglish, accountNumber: x.accountNumber } });
        console.log(response);
      }
    })
  }
  initForm() {
    this.bankTransferForm = this.fb.group({
      bankArray: this.fb.array([this.bankFormControls()])
    })
    if (this.recentFormValues?.bankTransfer?.bankArray?.length) {
      let values = this.recentFormValues['bankTransfer'].bankArray
      let formArray = (this.bankTransferForm.get('bankArray') as FormArray);
      formArray.removeAt(0)
      for (let item of values) {
        formArray.push(this.bankFormControls(item))
      }
      let filesSub = this._subjectService.bankTransferFiles.subscribe(files => {
        if (files?.length > 0) {
          this.filesArray = files;
        }
      })
      this.filesSubscription.add(filesSub);
    }
  }
  ngOnDestroy() {
    if (this.recentFormValues?.bankTransfer?.bankArray[0]?.paidAmountJod > 0) {
      this.formValueEvent.emit({ values: this.bankTransferForm.getRawValue(), touched: false })
      this._subjectService.bankTransferFiles.next(this.filesArray);
      this.filesSubscription.unsubscribe();
    }
  }
  handleAmountFocus() {
    this.bankTransferForm.markAllAsTouched();
  }
  bankFormControls(item?) {
    if (item) {
      return this.fb.group({
        sameCustomer: [item?.sameCustomer],
        paidAmountJod: [item?.paidAmountJod, [Validators.min(0.0000000000000001), Validators.required]],
        transfereDate: [item?.transfereDate, [Validators.required]],
        markaziaBankAccountId: [item?.markaziaBankAccountId, [Validators.required]],
        transfereReference: [item?.transfereReference, [Validators.required, Validators.pattern('^[0-9]*$')]],
        transfereAttachment: [item?.transfereAttachment],
        attachment: [item?.attachment],
        cardPayerName: [item?.cardPayerName, this.otherData.collectionType != 7004 && [Validators.required]],
        currencyId: [item?.currencyId, [Validators.required]],
        isReversed: [(item?.isReversed ?? item?.isReversed) || false],
        isNew: [(item?.isNew ?? item?.isNew) || false],
        lineNew: [(item?.lineNew ?? item?.lineNew) || false],
      });
    }
    else {
      return this.fb.group({
        sameCustomer: [true],
        paidAmountJod: ['', [Validators.min(0.0000000000000001), Validators.required]],
        transfereDate: [(new Date()).toISOString().substring(0, 10), [Validators.required]],
        markaziaBankAccountId: [null, [Validators.required]],
        transfereReference: ['', [Validators.required, Validators.pattern('^[0-9]*$')]],
        transfereAttachment: [''],
        attachment: [''],
        cardPayerName: [localStorage.getItem('pmcn') || 'No Customer', this.otherData.collectionType != 7004 && [Validators.required]],
        currencyId: [9001, [Validators.required]],
        isReversed: [false],
        isNew: [true],
        lineNew: [true],
      });
    }
  }
  fileAction(fileName, index, action) {
    if (action == 'view') {
      const modelRef = this._modalService.open(ViewFileComponent, { size: 'md' });
      let isReversed = (this.bankArrControls.at(index) as FormGroup).get('isReversed').getRawValue();
      let isNew = (this.bankArrControls.at(index) as FormGroup).get('isNew').getRawValue();
      if (!this.otherData?.reverse || isReversed === false) {
        let file = this.filesArray[index];
        if (isNew)
          modelRef.componentInstance.imageUploadedView = file;
        else
          modelRef.componentInstance.imageUploadedView = { viewOnly: true, url: file };
      }
      else {
        // IN CASE OF REVERSE ONLY
        if (isReversed === null || isReversed) {
          let file = this.filesArray[index];
          modelRef.componentInstance.imageUploadedView = { viewOnly: true, url: file }
        }
      }
    }
    else {
      if (this.otherData?.reverse) {
        let isNew = this.bankArrControls.at(index).get('isNew').getRawValue();
        if (!isNew) return;
      }
      this.filesArray.splice(index, 1, {});
      let inputRef = this.inputRefList.toArray()[index] as ElementRef;
      (this.bankTransferForm.get('bankArray') as FormArray).at(index).get('attachment')?.setValue('');
      (this.bankTransferForm.get('bankArray') as FormArray).at(index).get('transfereAttachment')?.setValue('');
      inputRef.nativeElement.value = null;
      this.removeFileFromLocalStorage(index);
    }
  }
  removeFileFromLocalStorage(index) {
    let files = localStorage.getItem('bpUploadedFiles');
    if (files) {
      this.uploadedFiles = [...JSON.parse(localStorage.getItem('btUploadedFiles'))];
      this.uploadedFiles.splice(index, 1, 'noFile');
      localStorage.setItem('btUploadedFiles', JSON.stringify(this.uploadedFiles));
    }
  }
  onFileChange(event, i) {
    let files = [...event.target.files];
    //this.filesArray.splice(i, 1);
    let formArray = (this.bankTransferForm.get('bankArray') as FormArray);
    if (files.length > 0) {
      let isInvalid = this.checkInvalidImageFormat(files);
      if (!isInvalid) {
        files.forEach((file: File) => {
          this.uploadFile(file, i);
          this._commonService.fileToBase64(file).then(response => {
            this.filesArray.splice(i, 1, response)
            formArray.at(i).get('attachment')?.setValue('Attachment');
          })
        })
      }
    }
  }
  uploadFile(file, index) {
    const formData = new FormData();
    formData.append('Folder', 'BankTransfer');
    formData.append('File', file);
    this._collectService.uploadFile(formData).subscribe(response => {
      if (response.isSuccess) {
        this.uploadedFiles.splice(index, 1, response['data']);
        (this.bankTransferForm.get('bankArray') as FormArray).at(index).get('transfereAttachment')?.setValue(response['data']);
        localStorage.setItem('btUploadedFiles', JSON.stringify(this.uploadedFiles));
      }
    })
  }
  checkInvalidImageFormat(data) {
    let files;
    let getFiles = data.map(x => {
      return x.file
    })
    if (getFiles[0] !== undefined) {
      files = getFiles;
    }
    else {
      files = data;
    }
    let invalidExtentions = false;
    for (let file of files) {
      if (!this.fileTypes.includes(file.type)) {
        invalidExtentions = true;
        this.invalidFileType = 'This file not support, supported formates: JPEG, JPG, PNG, PDF';
        this.bankTransferForm.get('attachment')?.patchValue('');
        setTimeout(() => this.invalidFileType = '', 3000)
        break;
      }
    }
    return invalidExtentions;
  }
  removeItem(i) {
    if (this.otherData.refund) return;
    this.filesArray.splice(i, 1);
    this.bankArrControls.removeAt(i);
    this.removeFileFromLocalStorage(i);
    this.sendAmount();
  }
  get bankArrControls() {
    return this.bankTransferForm ? this.bankTransferForm.get('bankArray') as FormArray : null;
  }
  handleTabKeyDown() {
    if (this.otherData.refund || this.bankTransferForm.invalid) {
      return;
    }
    if (this.otherData['amountExceeded']) {
      return;
    }
    if (!this.otherData?.isMultiCollect)
      this.addNewRow();

  }
  addNewRow() {
    this.bankArrControls.push(this.bankFormControls());
    this.bankTransferForm.markAsUntouched();
  }
  isSameCustomer(event, index) {
    let formGroup = this.bankArrControls.at(index) as FormGroup;
    if (event.target.checked) {
      if (this.otherData.collectionType == 7004) {
        formGroup.controls['cardPayerName'].setValue('No Customer');
      }
      else {
        let customerName = localStorage.getItem('pmcn');
        formGroup.controls['cardPayerName'].setValue(customerName);
      }
    }
    else {
      formGroup.controls['cardPayerName'].setValue('');
    }
  }
  handleSubmit() {
    if (this.bankTransferForm.invalid) {
      this.bankTransferForm.markAllAsTouched();
    }
    else {
      console.log(this.bankTransferForm.getRawValue());
      this.formValueEvent.emit({ values: this.bankTransferForm.getRawValue(), submit: true })
    }
  }
  get f() {
    return this.bankTransferForm.controls;
  }
  sendAmount() {
    this.calculateAmount();
  }
  calculateAmount() {
    let amount = 0;
    for (let item of this.bankArrControls.controls) {
      let formGroup = item as FormGroup;
      amount += +(formGroup.controls['paidAmountJod'].getRawValue());
    }
    this.amountEvent.emit({ amount });
  }
  reverse(item: AbstractControl, index: number) {
    const previousFormGroup = this.bankArrControls.at(index) as FormGroup;
    const newFormGroup = this.fb.group({});
    Object.keys(previousFormGroup.controls).forEach(controlName => {
      const controlValue = _.cloneDeep(previousFormGroup.get(controlName)?.value);
      newFormGroup.addControl(controlName, new FormControl(controlValue));
    });
    let negativeValue = (previousFormGroup.get('paidAmountJod').value) * -1;
    newFormGroup.patchValue({
      paidAmountJod: negativeValue,
      isReversed: true,
      lineNew: true,
    })
    previousFormGroup.get('isReversed').setValue(true);
    previousFormGroup.get('lineNew').setValue(false);
    this.bankArrControls.insert(index + 1, newFormGroup);
    let attachment = this.filesArray[index];
    this.filesArray.splice(index + 1, 0, attachment);
    (this.bankArrControls.at(index) as FormGroup).disable();
    (this.bankArrControls.at(index + 1) as FormGroup).disable();
    this.sendAmount();
  }
  resetForm() {
    this.bankArrControls.clear();
    this.bankArrControls.push(this.bankFormControls())
    this.bankTransferForm.markAsUntouched();
    this.formValueEvent.emit({ values: this.bankTransferForm.getRawValue(), touched: false, reset: true });
    this.amountEvent.emit({ amount: 0 });
  }
  closeModal() {
    if (this._activeModal)
      this._activeModal.close()
    else
      this._commonService.NavigateToRoute(`/${this.otherData?.redirectRoute}`)
  }

}

