import { Component, EventEmitter, Input, OnInit, Output } from '@angular/core';
import { Router } from '@angular/router';
import { NgbActiveModal, NgbModal } from '@ng-bootstrap/ng-bootstrap';
import { SubjectService } from '../../../../../../services/subject.service';

@Component({
  selector: 'app-modal-pay-done',
  templateUrl: './modal-pay-done.component.html',
  styleUrls: ['./modal-pay-done.component.scss'],
})
export class ModalPayDoneComponent implements OnInit {
  @Input() name;
  @Input() data;
  @Input() errors;
  @Input() response;
  @Input() routeName;
  @Input() notAutoDismiss;
  @Output() eventData = new EventEmitter();
  constructor(
    private router: Router,
    private modalService: NgbModal,
    public activeModal: NgbActiveModal,
    public _subjectService: SubjectService
  ) { }

  ngOnInit(): void {
    if (this.name == 'ok') {
      setTimeout(() => {
        //this.modalService.dismissAll();
        //this.router.navigateByUrl('/collect');
        //  window.location.reload()
      }, 4000);
    } else if (this.name == 'remain') {
      setTimeout(() => {
        // this.modalService.dismissAll();
      }, 4000);
    } else {
      setTimeout(() => {
        // this.modalService.dismissAll();
      }, 4000);
    }
  }
  navigateTo() {
    if (this.data?.collectionType !== 7008) {
      this.modalService.dismissAll();
      //this.router.navigateByUrl('/collect');
      if (this.routeName) this.router.navigateByUrl(`/${this.routeName}`);
      else this._subjectService.isCollectionPaymentDone.next(true);
    }
  }
  emitData() {
    if (this.data?.collectionType == 7008) {
      this._subjectService.paymentDoneModalClosed.next({ closed: true });
    }
  }
  downloadInvoices() {
    let isArray = Array.isArray(this.response.data);
    if (isArray) {
      this.response.data.forEach(x => {
        this.iterateData(x);
      })
    }
    else {
      this.iterateData(this.response.data)
    }
    if (!this.notAutoDismiss) {
      setTimeout(() => {
        if (this.routeName) this.router.navigateByUrl(`/${this.routeName}`);
        else this._subjectService.isCollectionPaymentDone.next(true);
        this.modalService.dismissAll();
      }, 3000)
    }
    else {
      if (this.routeName) this.router.navigateByUrl(`/${this.routeName}`);
    }
  }
  iterateData(data) {
    for (let key in data) {
      let item = data[key];
      if (item) {
        setTimeout(() => {
          this.downloadURI(item)
        }, 500)
      }
    }
  }
  downloadURI(uri: string) {
    let name = uri.split('/').pop();
    var link = document.createElement("a");
    //link.setAttribute('download', name);
    link.setAttribute('target', '_blank');
    link.href = uri;
    document.body.appendChild(link);
    link.click();
    link.remove();
  }
}
