import { Component, EventEmitter, Input, Output } from '@angular/core';
import { FormControl, Validators } from '@angular/forms';
import { NgbActiveModal } from '@ng-bootstrap/ng-bootstrap';

@Component({
  selector: 'app-terminal-provider-modal',
  templateUrl: './terminal-provider-modal.component.html',
  styleUrls: ['./terminal-provider-modal.component.scss']
})
export class TerminalProviderModalComponent {
  @Input() data;
  @Output() eventData = new EventEmitter();
  providerMachineID = new FormControl(null, [Validators.required]);
  constructor(
    public _activeModal: NgbActiveModal,

  ) { }
  handleConfirmClick() {
    if (!this.providerMachineID.valid) {
      this.providerMachineID.markAllAsTouched();
      return;
    }
    this.eventData.emit({ ...this.providerMachineID.value });
  }
}
