import { ChangeDetectorRef, Component, EventEmitter, Input, Output, SimpleChange, SimpleChanges, ViewChild } from '@angular/core';
import { FormBuilder, FormGroup, Validators } from '@angular/forms';
import { NgbModal } from '@ng-bootstrap/ng-bootstrap';
import { CommonService } from '../../../../../../services/common.service';
import { SharedService } from '../../../../../../services/shared.service';
import { CollectService } from '../../services/collect.service';
import { AddNewCustomerComponent } from './components/add-new-customer/add-new-customer.component';
import { catchError, forkJoin, of } from 'rxjs';
import { MarkaziaVoucherService } from '../../../markazia-vouchers/services/markazia-voucher.service';
import { SubjectService } from '../../../../../../services/subject.service';
import { GeneralService } from '../../../../../../services/general.service';
import { ModalMessageComponent } from '../../../../../../shared/components/modal-message/modal-message.component';

@Component({
  selector: 'otherRevenueForm',
  templateUrl: './other-revenue-form.component.html',
  styleUrls: ['./other-revenue-form.component.scss']
})
export class OtherRevenueFormComponent {
  revenueForm: FormGroup;
  emittedValues;
  categories;
  customers;
  @Input() data;
  costCenterList = [];
  taxesList = [];
  noTotalAmount = false;
  @Output() calcRevenueRemainingAmount: EventEmitter<any> = new EventEmitter();
  constructor(private fb: FormBuilder,
    private _vocuherService: MarkaziaVoucherService,
    private collectService: CollectService,
    private _subjectService: SubjectService,
    private _generalService: GeneralService,
    private cdRef: ChangeDetectorRef,
    public sharedService: SharedService, private _commonService: CommonService, private _modalService: NgbModal) { }
  ngOnInit() {
    this.initRevenuForm();
    this.getCategories();
    //this.getCustomers();
    this.getLookups();
  }
  ngOnChanges(changes: SimpleChanges) {
    console.log(changes);
    if (changes['data']) {
      let value = changes['data'].currentValue?.totalCollectedAmount;
      if (value > 0) {
        this.calcuateTaxAndAmountFromTotalAmount(value)
      }

    }
  }
  initRevenuForm() {
    this.revenueForm = this.fb.group({
      customerId: [null],
      customerName: ['', this.data.collectionType == 7005 && [Validators.required]],
      revenueCategoryId: [null, [Validators.required]],
      costCenterId: [null, this.data.collectionType == 7004 && [Validators.required]],
      amount: [null, [Validators.min(0.0000000000000001), Validators.required]],
      tax: [null, Validators.required],
      taxPercent: '',
      taxAmount: '',
      totalAmount: '',
      mobile: '',
      note: [''],
    })
  }
  calcuateTaxAndAmountFromTotalAmount(totalAmount) {
    let taxPercentage = +this.f['taxPercent'].value;
    const taxAmount = (((+totalAmount) * taxPercentage) / 100).toFixed(3);
    const amount = (totalAmount - (+taxAmount)).toFixed(3);
    this.f['taxAmount'].setValue(taxAmount);
    this.f['amount'].setValue(amount);
    this.f['totalAmount'].setValue(totalAmount);
    let formValue = this.revenueForm.value;
    formValue = { ...formValue, totalAmount: +totalAmount, amount: +formValue['amount'] };
    this.calcRevenueRemainingAmount.emit({ formValue, noTotalAmount: true });
  }
  handleNoAmountChange(event) {
    this.noTotalAmount = event.target.checked;
    let value = { ...this.revenueForm.value }
    if (this.noTotalAmount) {
      let obj = { revenueCategoryId: value.revenueCategoryId, tax: value.tax, taxPercent: value.taxPercent }
      if (this.data.collectionType == 7004 || this.data.collectionType == 7005) {
        obj['customerId'] = value.customerId;
        obj['customerName'] = value.customerName;
      }
      this.revenueForm.reset(obj);
      this.calcRevenueRemainingAmount.emit({ noTotalAmount: true });
    }
    else {
      this.calcRevenueRemainingAmount.emit({ formValue: {}, amount: 0 });
    }
    this.toggleValidation();
  }
  toggleValidation() {
    let amountControl = this.f['amount'];
    if (this.noTotalAmount) {
      amountControl.removeValidators([Validators.required]);
    }
    else {
      amountControl.addValidators([Validators.required]);
    }
    amountControl.updateValueAndValidity();
  }
  responseModal(type, message) {
    const modalRef = this._modalService.open(ModalMessageComponent);
    modalRef.componentInstance.type = type;
    modalRef.componentInstance.message = message;
  }
  getLookups() {
    const costCenter = this._vocuherService.getCostCenter(`?StatusId=2001&PageSize=1000`).pipe(catchError(error => of(error)));
    let params = `?lookupTypeId=23&status=2001&pageSize=1000`;
    const taxes = this._generalService.getLookupsWithParams(params)
    forkJoin([costCenter, taxes]).subscribe(data => {
      this.costCenterList = data[0].data;
      this.taxesList = (data[1] as any).data.map(x => {
        return {
          ...x,
          text: x.name[0].lookupName
        }
      });
    })
  }
  handleTaxChange(event) {
    if (event) {
      this.revenueForm.get('taxPercent').setValue(event.text);
      this.calcTotalAmount();
    }
    else {
      this.noTotalAmount = false;
      this.toggleValidation();
      this.calcRevenueRemainingAmount.emit({ formValue: {}, amount: 0 });
    }

  }
  searchForCustomer() {
    let modalRef = this._modalService.open(AddNewCustomerComponent, {
      size: 'lg',
    })
    modalRef.componentInstance.sendData.subscribe(data => {
      let corporate = data?.corporateName;
      let individual = `${data?.fname} ${data?.sname} ${data?.thName} ${data?.fourthName}`
      let obj = { customerId: data?.customerNo, customerName: corporate || individual, mobile: data?.mobile }
      localStorage.setItem('pmcn', obj?.customerName);
      this.revenueForm.patchValue(obj);
      if (this.emittedValues) {
        let formValue = { ...this.emittedValues?.['formValue'], ...obj, };
        this.emittedValues = { ...this.emittedValues, formValue };
        if (this.emittedValues?.['formValue']['revenueCategoryId'])
          this.calcRevenueRemainingAmount.emit({...this.emittedValues,fromCustomer:true});
      }
    })
  }
  calcTotalAmount() {
    let amount = this.revenueForm.get('amount').value;
    if (amount > 0) {
      let taxAmount = (+(this.revenueForm.get('taxPercent').value) * amount) / 100;
      this.revenueForm.get('taxAmount').patchValue(this._commonService.transformDecimal(taxAmount));
      let totalAmount = +(this.revenueForm.get('amount').value) + (+(taxAmount));
      this.revenueForm.get('totalAmount').setValue(this._commonService.transformDecimal(totalAmount));
      let formValues = this.revenueForm.value;
      formValues = { ...formValues, totalAmount: +totalAmount, amount: formValues['amount'] };
      this.noTotalAmount = false;
      this.emittedValues = { formValue: formValues, amount: +totalAmount, noTotalAmount: false }
      if (this.data.collectionType == 7004) {
        if (formValues['revenueCategoryId'])
          this.calcRevenueRemainingAmount.emit(this.emittedValues);
      }
      else {
        if (formValues['customerId'] && formValues['revenueCategoryId'])
          this.calcRevenueRemainingAmount.emit(this.emittedValues);
      }
    }
    else {
      this.revenueForm.get('totalAmount').patchValue('');
      this.calcRevenueRemainingAmount.emit({ formValue: {}, amount: 0 });
    }
  }
  chooseCategory(e) {
    this.revenueForm.markAllAsTouched();
    this.revenueForm.get('taxPercent').patchValue(e?.taxPercent);
    this.revenueForm.get('tax').setValue(e?.taxPercentId);
    this.revenueForm.get('note').patchValue(e?.note);
    let taxId = +this.revenueForm.get('tax').value;
    let taxPercentage = +(this.taxesList.find(x => x.id == taxId)?.name[0]?.lookupName);
    let amount = +this.revenueForm.get('amount').value;
    let taxAmount = (taxPercentage / 100) * amount;
    this.revenueForm.get('taxAmount').patchValue(this._commonService.transformDecimal(taxAmount));
    let totalAmount = amount + taxAmount;
    this.revenueForm.get('totalAmount').patchValue(this._commonService.transformDecimal(totalAmount));
    let formValues = this.revenueForm.value;
    formValues = { ...formValues, totalAmount: +totalAmount, amount: formValues['amount'] };
    this.emittedValues = { formValue: formValues, amount: +totalAmount };
    if (!this.noTotalAmount) {
      if (this.data.collectionType == 7004) {
        if (formValues['revenueCategoryId'])
          this.calcRevenueRemainingAmount.emit(this.emittedValues);
      }
      else {
        if (formValues['customerId'] && formValues['revenueCategoryId'])
          this.calcRevenueRemainingAmount.emit(this.emittedValues);
      }
    }
  }
  clearCategory(e) {
    if (!e) {
      this.noTotalAmount = false;
      this.toggleValidation();
    }
    this.revenueForm.get('taxPercent').patchValue(0);
    this.revenueForm.get('tax').patchValue(null);
    this.revenueForm.get('totalAmount').patchValue(0);
    let revenueCategoryId = null
    this.emittedValues = { formValue: { ...this.revenueForm.value, revenueCategoryId }, amount: 0 }
    this.calcRevenueRemainingAmount.emit(this.emittedValues);
  }
  get f() {
    return this.revenueForm.controls;
  }
  getCustomers() {
    return this.collectService
      .customersList('')
      .subscribe((response: any) => {
        if (response) {
          this.customers = response.data;
        }
      });
  }

  getCategories() {
    if (this.data['collectionType'] == 7004) {
      this.collectService.GetCategories().subscribe((response: any) => {
        if (response) {
          this.categories = response.data;
          console.log(this.categories);
        }
      });
    }
    else {
      this.collectService.getCustomerPaymentCategories().subscribe((response: any) => {
        if (response) {
          this.categories = response.data;
        }
      });
    }
  }
}
